package main

import (
	"sort"
)

func solve(nums []int64, k int64) int64 {
	n := len(nums)
	if n == 0 {
		return 0
	}
	sortedNums := make([]int64, n)
	copy(sortedNums, nums)
	sort.Ints(sortedNums)
	maxLen := 1
	for i := 0; i < n; i++ {
		target := sortedNums[i] * k
		left := i
		right := n - 1
		res := i - 1
